const webhookBody = $('Webhook').first().json.body;
const data = $('Supabase - Get All Data').first().json || {};

// Default conversation state
const defaultState = {
  phase: 'topic_selection',
  selected_topics: [],
  current_topic_index: 0,
  current_question_index: 0,
  answers: {}
};

let conversationState = defaultState;

// PRIORITY 1: Try to get state from webhook (frontend sends it)
if (webhookBody.state && typeof webhookBody.state === 'object') {
  conversationState = webhookBody.state;
  console.log('Using state from webhook');
} else if (typeof webhookBody.state === 'string' && webhookBody.state.trim()) {
  try {
    conversationState = JSON.parse(webhookBody.state);
    console.log('Parsed state from webhook string');
  } catch (e) {
    console.log('Could not parse webhook state string');
  }
}

// PRIORITY 2: If still default, fetch from Supabase database
if (JSON.stringify(conversationState) === JSON.stringify(defaultState)) {
  try {
    const session_id = webhookBody.session_id;
    const agent_id = webhookBody.agent_name || 'newsletter_multi';

    const supabaseUrl = 'https://aoteeitreschwzkbpqyd.supabase.co';
    const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImFvdGVlaXRyZXNjaHd6a2JwcXlkIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc0NDEyMDAzNCwiZXhwIjoyMDU5Njk2MDM0fQ.EfXz8Rv_6yvI4MTDk5WoKSQ0E0jxoO3oWEMO-xAEtWU';

    const response = await fetch(
      `${supabaseUrl}/rest/v1/agent_conversation_state?session_id=eq.${encodeURIComponent(session_id)}&agent_id=eq.${encodeURIComponent(agent_id)}&status=eq.active&select=state`,
      {
        headers: {
          'apikey': supabaseKey,
          'Authorization': `Bearer ${supabaseKey}`
        }
      }
    );

    const stateData = await response.json();
    if (stateData && stateData.length > 0 && stateData[0].state) {
      conversationState = stateData[0].state;
      console.log('Loaded state from database:', conversationState);
    } else {
      console.log('No state in database, using default');
    }
  } catch (err) {
    console.log('State fetch error:', err.message);
  }
}

return [{
  json: {
    // Webhook identifiers
    user_id: webhookBody.user_id,
    user_mssg: webhookBody.user_mssg,
    session_id: webhookBody.session_id,
    agent_name: webhookBody.agent_name,
    timestamp_of_call_made: webhookBody.timestamp_of_call_made,
    request_id: webhookBody.request_id,

    // KB data (from combined view)
    knowledge_base: data.knowledge_base || '',
    knowledge_base_summary: (data.knowledge_base || '').substring(0, 2000),
    website_url: data.website_url || '',
    website_icon: data.favicon_url || '',
    communication_tone: data.communication_tone || 'professional',
    newsletter_instructions: data.newsletter_questions || '',

    // Topics data (from combined view)
    available_topics_display: data.available_topics_display || '',
    available_topics_text: data.available_topics_text || '',
    topics_with_questions: JSON.stringify(data.topics_with_questions || [], null, 2),
    topics_questions_formatted: data.topics_questions_formatted || '',
    topic_code_map: data.topic_code_map || {},
    total_topics: data.total_topics || 7,

    // Conversation state (FROM DB or default)
    conversation_state: JSON.stringify(conversationState, null, 2)
  }
}];

