// ============================================================================
  // Save Conversation State to Supabase - Multi-Topic Newsletter
  // ============================================================================

  const preparedData = $('Code - Prepare Data').first().json;
  const aiOutput = $('AI Agent - Conversation').first().json.output;

  const session_id = preparedData.session_id;
  const agent_id = preparedData.agent_name || 'newsletter_multi';
  const user_id = preparedData.user_id;

  // Get the new state from AI output
  const newState = aiOutput.state || {
    phase: 'topic_selection',
    selected_topics: [],
    current_topic_index: 0,
    current_question_index: 0,
    answers: {}
  };

  const status = aiOutput.Status === 'Ready' ? 'completed' : 'active';

  try {
      const supabaseUrl = 'https://aoteeitreschwzkbpqyd.supabase.co';
      const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImFvdGVlaXRyZXNjaHd6a2JwcXlkIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc0NDEyMDAzNCwiZXhwIjoyMDU5Njk2MDM0fQ.EfXz8Rv_6yvI4MTDk5WoKSQ0E0jxoO3oWEMO-xAEtWU';

    // Upsert state (insert or update on conflict)
    const response = await fetch(`${supabaseUrl}/rest/v1/agent_conversation_state`, {
      method: 'POST',
      headers: {
        'apikey': supabaseKey,
        'Authorization': `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json',
        'Prefer': 'resolution=merge-duplicates'
      },
      body: JSON.stringify({
        session_id: session_id,
        agent_id: agent_id,
        firm_user_id: user_id,
        state: newState,
        status: status,
        updated_at: new Date().toISOString()
      })
    });

    if (response.ok) {
      console.log('State saved successfully:', { session_id, agent_id, phase: newState.phase });
    } else {
      const errorText = await response.text();
      console.log('State save response:', errorText);
    }
  } catch (err) {
    console.log('State save error:', err.message);
  }

  // Pass through unchanged
  return $input.all();
